import { useSelector } from "react-redux";
import bookIcon from "../assets/book-icon.svg"; // Adjust the path based on your folder structure
import "./styles.css";

function Home() {
  const user = useSelector((state) => state.auth.user);

  return (
    <div className="app-container">
      <nav className="navbar">
        <div className="navbar-brand">School App</div>
        <ul className="navbar-nav">
          <li><a href="/" className="nav-link">Главная</a></li>
          <li><a href="/logout" className="nav-link">Выход</a></li>
          <li><a href="/register" className="nav-link">Регистрация</a></li>
        </ul>
      </nav>
      <div className="container mt-5 text-center">
        <div className="title-wrapper">
          <h1 className="title">School App</h1>
          <img src={bookIcon} alt="Book Icon" className="book-icon" />
        </div>
        {user ? (
          <p className="lead">
            Здравствуйте, {user.name}! Вы вошли как {user.role}.
          </p>
        ) : (
          <div className="auth-section">
            <p className="lead">
              Пожалуйста,{" "}
              <a href="/login" className="btn btn-primary">
                войдите
              </a>{" "}
              или{" "}
              <a href="/register" className="btn btn-primary">
                зарегистрируйтесь
              </a>
              .
            </p>
          </div>
        )}
      </div>
    </div>
  );
}

export default Home;
